42: func getFlusher(w http.ResponseWriter) (http.Flusher, error) {
43: 	wrapper, ok := w.(*metrics.ResponderWrapper)
44: 	if !ok {
45: 		return nil, fmt.Errorf("expected ResponseWriter to be of type *metrics.ResponseWrapper: %T", w)
46: 	}
