73: func (h *getMapNameEventsHandler) Handle(params restapi.GetMapNameEventsParams) middleware.Responder {
74: 	follow := false
75: 	if params.Follow != nil {
76: 		follow = *params.Follow
77: 	}
78: 	m, exists := h.mapGetter.GetMap(params.Name)
79: 	if !exists || !m.IsEventsEnabled() {
80: 		return restapi.NewGetMapNameNotFound()
81: 	}
82: 
83: 	return middleware.ResponderFunc(func(w http.ResponseWriter, _ runtime.Producer) {
84: 		flusher, err := getFlusher(w)
85: 		if err != nil {
86: 			h.logger.WithError(err).Error("BUG: could not get flushed from ResponseWriter")
87: 			w.WriteHeader(http.StatusInternalServerError)
88: 			return
89: 		}
90: 
91: 		enc := json.NewEncoder(&flushWriter{f: flusher, w: w})
92: 
93: 		writeEventFn := func(e *bpf.Event) {
94: 			errStr := "<nil>"
95: 			if e.GetLastError() != nil {
96: 				errStr = e.GetLastError().Error()
97: 			}
98: 			err := enc.Encode(&models.MapEvent{
99: 				Key:           e.GetKey(),
100: 				Action:        e.GetAction(),
101: 				Value:         e.GetValue(),
102: 				LastError:     errStr,
103: 				Timestamp:     strfmt.DateTime(e.Timestamp),
104: 				DesiredAction: e.GetDesiredAction().String(),
105: 			})
106: 			if err != nil {
107: 				panic(err)
108: 			}
109: 			flusher.Flush()
110: 		}
111: 
112: 		handle, err := m.DumpAndSubscribe(writeEventFn, follow)
113: 		if err != nil {
114: 			h.logger.WithError(err).Error("api handler failed to subscribe to map events")
115: 			w.WriteHeader(http.StatusInternalServerError)
116: 			return
117: 		}
118: 
119: 		if follow && h != nil {
120: 			go func() {
121: 				<-params.HTTPRequest.Context().Done()
122: 				handle.Close()
123: 			}()
124: 			for e := range handle.C() {
125: 				writeEventFn(e)
126: 			}
127: 		}
128: 	})
129: }
