102: // writeInformationalComments writes annotations to the specified writer,
103: // including a base64 encoding of the endpoint object, and human-readable
104: // strings describing the configuration of the datapath.
105: //
106: // For configuration of actual datapath behavior, see WriteEndpointConfig().
107: //
108: // e.mutex must be RLock()ed
109: func (e *Endpoint) writeInformationalComments(w io.Writer) error {
110: 	fw := bufio.NewWriter(w)
111: 
112: 	fmt.Fprint(fw, "/*\n")
113: 	fmt.Fprintln(fw, " * This file is not using during compilation of endpoint programs.")
114: 
115: 	epStr64, err := e.base64()
116: 	if err == nil {
117: 		var verBase64 string
118: 		verBase64, err = version.Base64()
119: 		if err == nil {
120: 			// Current versions ignore the comment, but we need to retain it
121: 			// so that downgrades work.
122: 			fmt.Fprintln(fw, " * The line below is retained for backwards compatibility only.")
123: 			fmt.Fprintf(fw, " * %s%s:%s\n * \n", ciliumCHeaderPrefix,
124: 				verBase64, epStr64)
125: 		}
126: 	}
127: 	if err != nil {
128: 		e.logStatusLocked(BPF, Warning, fmt.Sprintf("Unable to create a base64: %s", err))
129: 	}
130: 
131: 	if cid := e.GetContainerID(); cid == "" {
132: 		fmt.Fprintf(fw, " * Docker Network ID: %s\n", e.dockerNetworkID)
133: 		fmt.Fprintf(fw, " * Docker Endpoint ID: %s\n", e.dockerEndpointID)
134: 	} else {
135: 		fmt.Fprintf(fw, " * Container ID: %s\n", cid)
136: 		fmt.Fprintf(fw, " * Container Interface: %s\n", e.containerIfName)
137: 	}
138: 
139: 	if e.parentIfIndex != 0 {
140: 		fmt.Fprintf(fw, " * Parent Interface IfIndex: %d\n", e.parentIfIndex)
141: 	}
142: 
143: 	if option.Config.EnableIPv6 {
144: 		fmt.Fprintf(fw, " * IPv6 address: %s\n", e.IPv6.String())
145: 	}
146: 	fmt.Fprintf(fw, ""+
147: 		" * IPv4 address: %s\n"+
148: 		" * Identity: %d\n"+
149: 		" * PolicyMap: %s\n"+
150: 		" * NodeMAC: %s\n"+
151: 		" */\n\n",
152: 		e.IPv4.String(),
153: 		e.getIdentity(), bpf.LocalMapName(policymap.MapName, e.ID),
154: 		e.nodeMAC)
155: 
156: 	fw.WriteString("/*\n")
157: 	fw.WriteString(" * Labels:\n")
158: 	if e.SecurityIdentity != nil {
159: 		if len(e.SecurityIdentity.Labels) == 0 {
160: 			fmt.Fprintf(fw, " * - %s\n", "(no labels)")
161: 		} else {
162: 			for _, v := range e.SecurityIdentity.Labels {
163: 				fmt.Fprintf(fw, " * - %s\n", v.String())
164: 			}
165: 		}
166: 	}
167: 	fw.WriteString(" */\n\n")
168: 
169: 	return fw.Flush()
170: }
